const query = $input.first().json.query || {};
return {
  user_id: parseInt(query.user_id) || 1,
  status:   query.status   || null,
  priority: query.priority || null,
  search:   query.search   || null,
  limit:  parseInt(query.limit)  || 50,
  offset: parseInt(query.offset) || 0
};

const body = $input.first().json.body || {};

if (!body.lead_id) throw new Error('lead_id is required');
if (!body.action)  throw new Error('action is required');

const validActions = ['mark_qualified','mark_contacted','mark_disqualified','mark_unsubscribed'];
if (!validActions.includes(body.action)) {
  throw new Error('Invalid action. Use: ' + validActions.join(', '));
}

return {
  lead_id: parseInt(body.lead_id),
  action:  body.action,
  notes:   body.notes || null
};

const query = $input.first().json.query || {};
return {
  job_id:  parseInt(query.job_id)  || null,
  user_id: parseInt(query.user_id) || 1
};

const p = $input.first().json;
return {
  success: true,
  staging: {
    total:          parseInt(p.staging_total)          || 0,
    pending:        parseInt(p.staging_pending)        || 0,
    done:           parseInt(p.staging_done)           || 0,
    no_email:       parseInt(p.staging_no_email)       || 0,
    no_email_final: parseInt(p.staging_no_email_final) || 0
  },
  cleaned: {
    total:       parseInt(p.total_cleaned) || 0,
    valid_emails:parseInt(p.valid_emails)  || 0,
    has_phone:   parseInt(p.has_phone)     || 0,
    has_email:   parseInt(p.has_email)     || 0
  },
  enriched: {
    stage1: parseInt(p.enriched_stage1) || 0,
    stage2: parseInt(p.enriched_stage2) || 0,
    stage3: parseInt(p.enriched_stage3) || 0
  },
  outreach: {
    email_sent:   parseInt(p.email_sent)   || 0,
    qualified:    parseInt(p.qualified)    || 0,
    disqualified: parseInt(p.disqualified) || 0,
    replied:      parseInt(p.replied)      || 0,
    sales_ready:  parseInt(p.sales_ready)  || 0
  }
};

const query = $input.first().json.query || {};
if (!query.lead_id) throw new Error('lead_id is required');
return { lead_id: parseInt(query.lead_id) };

const u = $input.first().json;
return {
  success: true,
  user: {
    id:                   u.id,
    email:                u.email,
    apify_status:         u.apify_status,
    apify_credit:         parseFloat(u.apify_credit) || 0,
    total_jobs:           parseInt(u.total_jobs)      || 0,
    completed_jobs:       parseInt(u.completed_jobs)  || 0,
    failed_jobs:          parseInt(u.failed_jobs)     || 0,
    running_jobs:         parseInt(u.running_jobs)    || 0,
    total_spent:          parseFloat(u.total_spent)   || 0,
    total_leads_scraped:  parseInt(u.total_leads_scraped) || 0,
    last_job_at:          u.last_job_at
  }
};
